def detect_type(start,end):
    window = s[max(0,start-64):min(len(s),end+64)]
    aya_cues = ['قال الله','يقول الله','قال تعالى','قال الله تعالى','الآية','سورة','قال تعالى','﴿','آية']
    had_cues = ['قال رسول','قال النبي','قال رسول الله','قال النبي ﷺ','في الحديث','رواه','أخرج','روى','عن النبي','النبي ﷺ','قال رسول الله']
    for c in aya_cues:
        if c in window:
            return "Aya"
    for c in had_cues:
        if c in window:
            return "Hadeeth"
    # fallback: if contains typical Quranic orthography or 'الله' maybe Aya
    if 'الله' in s[start:end]:
        return "Aya"
    return "Hadeeth"

